#include <stdio.h>
#include <math.h>
int count_prime_factors(int n) {
    int count = 0;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            count++;
            while (n % i == 0) n /= i;
        }
    }
    if (n > 1) count++;
    return count;
}
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) scanf("%d", &arr[i]);
    int classy_count = 0;
    for (int i = 0; i < n; i++) {
        if (count_prime_factors(arr[i]) == 3) classy_count++;
    }
    printf("%d\n", classy_count);
    return 0;
}

