        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) arr[i] = scanner.nextInt();
        int classy_count = 0;
        for (int i = 0; i < n; i++) {
            if (count_prime_factors(arr[i]) == 3) classy_count++;
        }
        System.out.println(classy_count);
    }
}

