def count_prime_factors(n):
    count = 0
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            count += 1
            while n % i == 0: n //= i
    if n > 1: count += 1
    return count

def main():
    n = int(input())
    arr = list(map(int, input().split()))
    classy_count = 0
    for num in arr:
        if count_prime_factors(num) == 3: classy_count += 1
    print(classy_count)

